- subsystem lanes use the same evidence model and closure language","status":"open","priority":0,"issue_type":"task","created_at":"2026-03-18T22:52:33.494280512Z","created_by":"ubuntu","updated_at":"2026-03-18T22:52:33.494280512Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["audit","program-management"],"dependencies":[{"issue_id":"br-97gc6.1","depends_on_id":"br-97gc6","type":"parent-child","created_at":"2026-03-18T22:52:33.494280512Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
